// This file has been autogenerated from a class added in the UI designer.

using System;

using Foundation;
using AppKit;

namespace AnalysisITC
{
	public partial class TextInputMeniItemView : NSView
	{
		public TextInputMeniItemView (IntPtr handle) : base (handle)
		{
		}

        partial void Action(NSTextField sender)
        {
            string token = sender.StringValue.Trim();

            // Ignore if token empty
            if (string.IsNullOrWhiteSpace(token)) return;

            Console.WriteLine($"Including data based on: {token}");

            // Inactivate all
            DataManager.Data.ForEach(d => d.Include = false);

            foreach (var data in DataManager.Data)
            {
                if (data.FileName.Contains(token) || data.Comments.Contains(token))
                    data.Include = true;

                data.UpdateProcessing(false);
            }

            DataManager.InvokeDataDidChange();
        }
    }
}
